#!/bin/bash
set -e
cd "$(dirname "$0")"

python3 -c "import base64; open('scripts/daily-agent.mjs', 'wb').write(base64.b64decode(''))"
echo "✅ scripts/daily-agent.mjs"
python3 -c "import base64; open('scripts/generate-article.mjs', 'wb').write(base64.b64decode(''))"
echo "✅ scripts/generate-article.mjs"
python3 -c "import base64; open('scripts/analyze-and-improve.mjs', 'wb').write(base64.b64decode(''))"
echo "✅ scripts/analyze-and-improve.mjs"

git add scripts/daily-agent.mjs scripts/generate-article.mjs scripts/analyze-and-improve.mjs
git commit -m "fix: auto-load .env.local + API error handling in all scripts"
git push origin main
echo ""
echo "🚀 Push完了！"
echo ""
echo "=== テスト実行 ==="
echo "node scripts/daily-agent.mjs --dry-run"
node scripts/daily-agent.mjs --dry-run